import{_ as n,o as e,c as r,ag as o}from"./chunks/framework.BZohXCq9.js";const u=JSON.parse('{"title":"Personas & User Journey — Vivu Travel","description":"","frontmatter":{},"headers":[],"relativePath":"99-tham-khao/archive/01-nen-tang-he-thong/00c-personas-user-journey.md","filePath":"99-tham-khao/archive/01-nen-tang-he-thong/00c-personas-user-journey.md"}'),a={name:"99-tham-khao/archive/01-nen-tang-he-thong/00c-personas-user-journey.md"};function i(d,t,s,h,l,c){return e(),r("div",null,[...t[0]||(t[0]=[o(`<h1 id="personas-user-journey-—-vivu-travel" tabindex="-1">Personas &amp; User Journey — Vivu Travel <a class="header-anchor" href="#personas-user-journey-—-vivu-travel" aria-label="Permalink to &quot;Personas &amp; User Journey — Vivu Travel&quot;">​</a></h1><blockquote><p><strong>Phiên bản:</strong> 1.0 · <strong>Ngày:</strong> 26/05/2026 · <strong>Tier:</strong> 1 (Business)</p><p>File này cụ thể hoá <strong>WHO</strong> trong <a href="./00-tam-nhin"><code>00-tam-nhin.md</code></a> thành 3 personas + journey map + service blueprint. Mỗi feature trong sprint phải serve ít nhất 1 persona — nếu không serve persona nào → có thể là tech-debt cleanup hoặc cần review.</p><p><strong>Quy tắc:</strong> persona đặt tên người Việt cụ thể (Anh Khoa, Chị Linh, Admin Vivu) để team dễ &quot;tưởng tượng&quot; và empathy. Không dùng tên abstract &quot;User A / User B&quot;.</p></blockquote><hr><h2 id="_1-3-personas-chinh" tabindex="-1">1. 3 personas chính <a class="header-anchor" href="#_1-3-personas-chinh" aria-label="Permalink to &quot;1. 3 personas chính&quot;">​</a></h2><h3 id="_1-1-anh-khoa-—-family-decision-maker-persona-chinh" tabindex="-1">1.1 Anh Khoa — Family Decision Maker (Persona chính) <a class="header-anchor" href="#_1-1-anh-khoa-—-family-decision-maker-persona-chinh" aria-label="Permalink to &quot;1.1 Anh Khoa — Family Decision Maker (Persona chính)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Thuộc tính</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Tuổi / Nghề</strong></td><td>32 tuổi, Kỹ sư phần mềm, TP.HCM</td></tr><tr><td><strong>Gia đình</strong></td><td>Vợ 29t + 2 con (6t, 3t), thỉnh thoảng dẫn ba mẹ đi cùng</td></tr><tr><td><strong>Thu nhập</strong></td><td>30-50tr/tháng, ngân sách du lịch ~50tr/năm</td></tr><tr><td><strong>Tần suất đi tour</strong></td><td>2-3 lần/năm (hè, Tết, lễ dài)</td></tr><tr><td><strong>Tech savvy</strong></td><td>Cao — dùng web + app thành thạo, có Google account, đã book Airbnb/Klook</td></tr><tr><td><strong>Device chính</strong></td><td>Desktop khi research, mobile khi book hoặc xem nhanh</td></tr><tr><td><strong>Kênh discover</strong></td><td>Google search &quot;tour [địa điểm] [N ngày] cho gia đình&quot;, group FB &quot;Du lịch cùng con&quot;</td></tr><tr><td><strong>Pain points</strong></td><td>• Sợ tour &quot;treo đầu dê bán thịt chó&quot; (mô tả khác thực tế)<br>• Phải gọi/chat operator nhiều mới chốt được giá<br>• Lo trẻ con không hợp lịch trình (đi quá nhiều)<br>• Sợ chuyển khoản tay rủi ro</td></tr><tr><td><strong>Goals</strong></td><td>• Tìm tour 4-6 ngày phù hợp gia đình có trẻ nhỏ<br>• So sánh 3-4 option nhanh<br>• Book online minh bạch, có hoá đơn</td></tr><tr><td><strong>Behavior</strong></td><td>• Đọc kỹ itinerary từng ngày<br>• Filter theo &quot;phù hợp trẻ em&quot;, &quot;có hotel 4★+&quot;<br>• Đọc review verified, đặc biệt review có ảnh<br>• Tham khảo vợ trước khi book → cần share link tour</td></tr><tr><td><strong>Quote</strong></td><td><em>&quot;Tôi muốn biết rõ mỗi ngày con tôi sẽ đi đâu, ăn gì, ngủ ở đâu — trước khi tôi quyết chi 30 triệu.&quot;</em></td></tr></tbody></table><p><strong>Feature ưu tiên cho Anh Khoa:</strong></p><ul><li>Trang detail tour phải có: gallery ảnh thực + itinerary từng ngày <ul><li>thông tin hotel cụ thể + chính sách trẻ em rõ ràng + review verified</li></ul></li><li>Filter &quot;phù hợp gia đình&quot;, &quot;có trẻ em&quot;, &quot;hotel ≥4 sao&quot;</li><li>Share link tour (preview đẹp khi paste vào Zalo/FB)</li><li>Payment chính thống (VNPay/MoMo) + email hoá đơn</li></ul><hr><h3 id="_1-2-chi-linh-—-young-professional-couple-traveler" tabindex="-1">1.2 Chị Linh — Young Professional / Couple Traveler <a class="header-anchor" href="#_1-2-chi-linh-—-young-professional-couple-traveler" aria-label="Permalink to &quot;1.2 Chị Linh — Young Professional / Couple Traveler&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Thuộc tính</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Tuổi / Nghề</strong></td><td>28 tuổi, Marketing Manager, Hà Nội</td></tr><tr><td><strong>Gia đình</strong></td><td>Single hoặc đi cùng bạn trai / nhóm bạn 4-6 người</td></tr><tr><td><strong>Thu nhập</strong></td><td>20-30tr/tháng, ngân sách du lịch ~30tr/năm</td></tr><tr><td><strong>Tần suất đi tour</strong></td><td>3-5 lần/năm (weekend escape + 1 chuyến lớn)</td></tr><tr><td><strong>Tech savvy</strong></td><td>Rất cao — mobile-first, IG/TikTok heavy user</td></tr><tr><td><strong>Device chính</strong></td><td>Mobile 80% — search, book, share đều trên điện thoại</td></tr><tr><td><strong>Kênh discover</strong></td><td>Instagram explore, TikTok &quot;destination VN aesthetic&quot;, Google quick search</td></tr><tr><td><strong>Pain points</strong></td><td>• Web travel tiếng Việt UX cũ, không mobile-friendly<br>• Tour package thường rườm rà với người không có gia đình<br>• Muốn flexibility (đổi ngày, đổi hotel) nhưng operator không cho</td></tr><tr><td><strong>Goals</strong></td><td>• Tìm weekend trip 2-3 ngày, vibe đẹp để post IG<br>• Book nhanh trên mobile<br>• Có thể save trip &quot;để xem sau&quot;</td></tr><tr><td><strong>Behavior</strong></td><td>• Lướt nhanh, scan ảnh nhiều hơn đọc<br>• Search by mood (&quot;núi rừng&quot;, &quot;biển vắng&quot;, &quot;phố cổ&quot;)<br>• Quan tâm review về ảnh đẹp + food + nightlife<br>• Hay save trip rồi 1-2 tuần sau mới quyết</td></tr><tr><td><strong>Quote</strong></td><td><em>&quot;Tôi muốn tour mà 30 giây nhìn ảnh là đã muốn book ngay, không phải đọc 5 trang mô tả.&quot;</em></td></tr></tbody></table><p><strong>Feature ưu tiên cho Chị Linh:</strong></p><ul><li>Mobile-first responsive cực ngon, hero image rich</li><li>Discovery theo &quot;vibe&quot; / collection (không chỉ filter theo địa lý)</li><li>&quot;Save / Wishlist&quot; tour (Phase 1.5 có thể defer — Phase 1 chấp nhận bookmark browser)</li><li>Booking flow tối ưu trên mobile (max 3 step, autofill, no friction)</li><li>Share preview đẹp (OG image dynamic per tour)</li></ul><hr><h3 id="_1-3-admin-vivu-—-internal-operator-persona-đac-biet" tabindex="-1">1.3 Admin Vivu — Internal Operator (Persona đặc biệt) <a class="header-anchor" href="#_1-3-admin-vivu-—-internal-operator-persona-đac-biet" aria-label="Permalink to &quot;1.3 Admin Vivu — Internal Operator (Persona đặc biệt)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Thuộc tính</th><th>Mô tả</th></tr></thead><tbody><tr><td><strong>Vai trò</strong></td><td>Operator nội bộ Vivu (Content, Ops, hoặc Founder kiêm)</td></tr><tr><td><strong>Số lượng dự kiến</strong></td><td>3-5 người Phase 1 (Founder + Content + Ops + Dev)</td></tr><tr><td><strong>Tech savvy</strong></td><td>Trung bình - cao — quen với CMS như WordPress, Excel, Google Sheets</td></tr><tr><td><strong>Device chính</strong></td><td>Desktop (~90%), thỉnh thoảng tablet</td></tr><tr><td><strong>Kênh</strong></td><td>Trực tiếp vào <code>/portal/*</code> (admin zone)</td></tr><tr><td><strong>Pain points</strong></td><td>• CMS rườm rà, nhiều click để tạo 1 tour<br>• Sửa nội dung mà không biết ai sửa khi (cần audit log)<br>• Upload ảnh chậm hoặc fail<br>• Lỡ tay xoá tour / destination không thể khôi phục<br>• Không biết tour nào đang bán chạy, conversion ra sao</td></tr><tr><td><strong>Goals</strong></td><td>• Tạo / cập nhật tour nhanh, ít click<br>• Theo dõi đơn booking realtime<br>• Quản lý lịch khởi hành + slot còn lại<br>• Update content SEO không cần dev support</td></tr><tr><td><strong>Behavior</strong></td><td>• Mỗi ngày check booking + email khách<br>• Mỗi tuần publish 2-3 tour mới hoặc cập nhật<br>• Mỗi tháng review SEO ranking + traffic</td></tr><tr><td><strong>Quote</strong></td><td><em>&quot;Tôi muốn tạo 1 tour trong 5 phút, sửa ảnh trong 1 phút, và biết ngay tour nào đang được khách quan tâm nhất tuần này.&quot;</em></td></tr></tbody></table><p><strong>Feature ưu tiên cho Admin Vivu:</strong></p><ul><li>Form CMS có validation Zod + toast error rõ ràng</li><li>Bulk upload ảnh Cloudinary + drag-reorder</li><li>Audit log (<code>ActivityLog</code>) cho mọi mutation</li><li>Soft delete bằng <code>isActive</code> (không xoá cứng) — đã có anchor V-05 cascade</li><li>Dashboard cơ bản: booking hôm nay, doanh thu tuần, tour hot</li><li>SEO override per entity (<code>SeoPage</code> polymorphic — đã có schema)</li></ul><hr><h2 id="_2-user-journey-—-anh-khoa-book-tour-gia-đinh-persona-chinh" tabindex="-1">2. User Journey — Anh Khoa book tour gia đình (Persona chính) <a class="header-anchor" href="#_2-user-journey-—-anh-khoa-book-tour-gia-đinh-persona-chinh" aria-label="Permalink to &quot;2. User Journey — Anh Khoa book tour gia đình (Persona chính)&quot;">​</a></h2><blockquote><p>Đây là <strong>happy path B2C</strong> — flow phải tối ưu cho 90% case. Edge case ở phần 4.</p></blockquote><h3 id="_2-1-journey-overview-5-phase" tabindex="-1">2.1 Journey overview (5 phase) <a class="header-anchor" href="#_2-1-journey-overview-5-phase" aria-label="Permalink to &quot;2.1 Journey overview (5 phase)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────┐   ┌──────────┐   ┌──────────┐   ┌──────────┐   ┌──────────┐</span></span>
<span class="line"><span>│ DISCOVER │ → │  BROWSE  │ → │  DETAIL  │ → │   BOOK   │ → │   POST   │</span></span>
<span class="line"><span>└──────────┘   └──────────┘   └──────────┘   └──────────┘   └──────────┘</span></span>
<span class="line"><span>   Google         Filter          Gallery        Form            Email</span></span>
<span class="line"><span>   Social         List            Itinerary      Payment         Tour</span></span>
<span class="line"><span>   Direct         Sort            Hotel info     Confirm         Review</span></span>
<span class="line"><span>                                  Review</span></span></code></pre></div><h3 id="_2-2-journey-chi-tiet-touchpoint-×-emotion-×-backend" tabindex="-1">2.2 Journey chi tiết (touchpoint × emotion × backend) <a class="header-anchor" href="#_2-2-journey-chi-tiet-touchpoint-×-emotion-×-backend" aria-label="Permalink to &quot;2.2 Journey chi tiết (touchpoint × emotion × backend)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Phase</th><th>Touchpoint (frontend)</th><th>Emotion</th><th>Vivu backend cần</th></tr></thead><tbody><tr><td><strong>1. Discover</strong></td><td>Google search &quot;tour Đà Lạt 4 ngày gia đình&quot; → click vào Vivu</td><td>Curious 🤔</td><td>SEO metadata + structured data + sitemap (anchor V-03)</td></tr><tr><td><strong>2. Browse</strong></td><td>Trang <code>/tours</code> lọc theo destination + giá + thời gian + &quot;phù hợp gia đình&quot;</td><td>Comparing 🧐</td><td>TourService.searchListings, filter index, cache page</td></tr><tr><td><strong>3. Detail</strong></td><td>Trang <code>/tours/[slug]</code> xem gallery, đọc itinerary từng ngày, xem hotel mỗi đêm, đọc review</td><td>Considering 🤓</td><td>TourService.getBySlug + itinerary + hotel info + review verified</td></tr><tr><td><strong>3.5 Compare</strong></td><td>Mở 2-3 tab so sánh tour, share link cho vợ qua Zalo</td><td>Validating 👫</td><td>OG image dynamic, page load nhanh, share preview đẹp</td></tr><tr><td><strong>4. Pick date</strong></td><td>Chọn lịch khởi hành (departure) còn slot phù hợp</td><td>Deciding 🗓️</td><td>TourDeparture với slot availability, anti-overbook</td></tr><tr><td><strong>5. Login / Register</strong></td><td>Bị redirect đăng nhập / đăng ký (anchor V-04 must-login)</td><td>Slight friction 😐</td><td>Auth flow tối ưu — Google OAuth 1-click, register 2-step</td></tr><tr><td><strong>6. Booking form</strong></td><td>Điền thông tin (tên, SDT, email, số người, ghi chú)</td><td>Focused ✍️</td><td>Validation Zod + pre-fill profile, snapshot pricing</td></tr><tr><td><strong>7. Payment</strong></td><td>VNPay / MoMo redirect, trả tiền, redirect back</td><td>Anxious 😰</td><td>Payment service, webhook idempotency, transaction safety</td></tr><tr><td><strong>8. Confirmation</strong></td><td>Trang cảm ơn + email confirm + mã đơn</td><td>Relief 😌</td><td>Email transactional, <code>Booking</code> saved, ActivityLog</td></tr><tr><td><strong>9. Pre-tour</strong></td><td>Email reminder 7 ngày + 1 ngày trước chuyến</td><td>Excited 🎒</td><td>Cron / scheduled email</td></tr><tr><td><strong>10. Tour</strong></td><td>Đi tour thực tế</td><td>(offline)</td><td>—</td></tr><tr><td><strong>11. Post-tour</strong></td><td>Email mời review + link verified review</td><td>Satisfied / Disappointed</td><td>Review service (chỉ user đã COMPLETED booking)</td></tr></tbody></table><h3 id="_2-3-hotspot-—-cho-de-rot-drop-off-risk" tabindex="-1">2.3 Hotspot — chỗ dễ rớt (drop-off risk) <a class="header-anchor" href="#_2-3-hotspot-—-cho-de-rot-drop-off-risk" aria-label="Permalink to &quot;2.3 Hotspot — chỗ dễ rớt (drop-off risk)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Phase</th><th>Drop-off risk</th><th>Mitigation Phase 1</th></tr></thead><tbody><tr><td>Browse → Detail</td><td>Page load chậm</td><td>SSR/ISR + image optimize</td></tr><tr><td>Detail → Pick date</td><td>Không có departure phù hợp</td><td>Suggest departure khác / destination tương tự</td></tr><tr><td>Pick date → Login</td><td><strong>Cao nhất</strong> — friction must-login (V-04)</td><td>Google OAuth 1-click, save state khi login để không mất context</td></tr><tr><td>Booking form → Payment</td><td>Form quá dài / lỗi validation</td><td>Pre-fill từ profile, validation realtime, error rõ ràng</td></tr><tr><td>Payment → Confirm</td><td>VNPay timeout / huỷ</td><td>Webhook retry + status PENDING + email recovery</td></tr></tbody></table><hr><h2 id="_3-service-blueprint-—-booking-flow-chi-tiet" tabindex="-1">3. Service Blueprint — Booking flow chi tiết <a class="header-anchor" href="#_3-service-blueprint-—-booking-flow-chi-tiet" aria-label="Permalink to &quot;3. Service Blueprint — Booking flow chi tiết&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ FRONTSTAGE (Customer thấy)                                          │</span></span>
<span class="line"><span>│                                                                     │</span></span>
<span class="line"><span>│  Trang detail   →  Booking widget  →  Form modal  →  Payment redirect│</span></span>
<span class="line"><span>│      ↓                  ↓                ↓                 ↓        │</span></span>
<span class="line"><span>│ ════════════════════════════════════════════════════════════════════│</span></span>
<span class="line"><span>│ BACKSTAGE (Vivu xử lý)                                              │</span></span>
<span class="line"><span>│                                                                     │</span></span>
<span class="line"><span>│  TourService     BookingService    AuthCheck      Payment Provider  │</span></span>
<span class="line"><span>│  .getBySlug      .createTour       requireUser    VNPay/MoMo SDK    │</span></span>
<span class="line"><span>│      ↓           Booking()             ↓                ↓           │</span></span>
<span class="line"><span>│  Prisma          Pessimistic lock   Supabase      Webhook listener │</span></span>
<span class="line"><span>│  query          TourDeparture        session       update status    │</span></span>
<span class="line"><span>│      ↓                ↓                 ↓                ↓          │</span></span>
<span class="line"><span>│ ════════════════════════════════════════════════════════════════════│</span></span>
<span class="line"><span>│ SUPPORT (Cross-cutting)                                             │</span></span>
<span class="line"><span>│                                                                     │</span></span>
<span class="line"><span>│  i18n message · ActivityLog · Email service · Cache invalidation    │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────────────┘</span></span></code></pre></div><hr><h2 id="_4-edge-cases-failure-modes" tabindex="-1">4. Edge cases &amp; failure modes <a class="header-anchor" href="#_4-edge-cases-failure-modes" aria-label="Permalink to &quot;4. Edge cases &amp; failure modes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Scenario</th><th>Behavior cần có Phase 1</th></tr></thead><tbody><tr><td>2 khách book cùng 1 slot cuối</td><td>Pessimistic lock → 1 win + 1 báo &quot;hết slot, chọn departure khác&quot;</td></tr><tr><td>Payment VNPay timeout</td><td>Booking PENDING → email khách &quot;thử lại&quot; + admin thấy trong dashboard</td></tr><tr><td>Khách book xong muốn huỷ</td><td>Phase 1: form contact admin (không tự huỷ); Phase 1.5: self-service theo policy</td></tr><tr><td>Khách quên password</td><td>Forgot password flow đã có</td></tr><tr><td>Admin xoá tour mà có booking pending</td><td><strong>Block xoá</strong> (FK constraint) hoặc soft delete <code>isActive=false</code> (V-05)</td></tr><tr><td>Admin xoá destination</td><td>Cascade hide cả tour/hotel xuống public (đã có cascade isActive)</td></tr><tr><td>SEO: tour đổi slug</td><td>SeoPage polymorphic theo entity ID (anchor V-03) → không orphan</td></tr><tr><td>Email khách không đến</td><td>Resend từ admin dashboard</td></tr><tr><td>Tour đang chạy thì hotel huỷ allotment</td><td>Manual: admin liên hệ khách swap hotel; không có flow tự động</td></tr></tbody></table><hr><h2 id="_5-persona-→-feature-priority-matrix" tabindex="-1">5. Persona → Feature priority matrix <a class="header-anchor" href="#_5-persona-→-feature-priority-matrix" aria-label="Permalink to &quot;5. Persona → Feature priority matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feature</th><th style="text-align:center;">Anh Khoa (Family)</th><th style="text-align:center;">Chị Linh (Young)</th><th style="text-align:center;">Admin Vivu</th></tr></thead><tbody><tr><td>Tour list + filter</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟡 (admin list)</td></tr><tr><td>Tour detail gallery</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟢</td><td style="text-align:center;">—</td></tr><tr><td>Itinerary từng ngày</td><td style="text-align:center;">🟢 critical</td><td style="text-align:center;">🟡</td><td style="text-align:center;">🟢 (CMS)</td></tr><tr><td>Hotel info gắn tour</td><td style="text-align:center;">🟢 critical</td><td style="text-align:center;">🟡</td><td style="text-align:center;">🟢 (CMS)</td></tr><tr><td>Filter &quot;phù hợp gia đình&quot;</td><td style="text-align:center;">🟢 critical</td><td style="text-align:center;">⚪</td><td style="text-align:center;">—</td></tr><tr><td>Mobile-first responsive</td><td style="text-align:center;">🟡</td><td style="text-align:center;">🟢 critical</td><td style="text-align:center;">🟡</td></tr><tr><td>OG image dynamic share</td><td style="text-align:center;">🟡</td><td style="text-align:center;">🟢 critical</td><td style="text-align:center;">—</td></tr><tr><td>Save / Wishlist</td><td style="text-align:center;">🟡</td><td style="text-align:center;">🟢</td><td style="text-align:center;">—</td></tr><tr><td>Payment chính thống</td><td style="text-align:center;">🟢 critical</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟢</td></tr><tr><td>Email confirm + reminder</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟢 (template CMS)</td></tr><tr><td>Review verified</td><td style="text-align:center;">🟢 critical</td><td style="text-align:center;">🟡</td><td style="text-align:center;">🟢 (moderation)</td></tr><tr><td>Audit log</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">🟢 critical</td></tr><tr><td>SEO override per entity</td><td style="text-align:center;">—</td><td style="text-align:center;">—</td><td style="text-align:center;">🟢 critical</td></tr><tr><td>Loyalty point (Phase 1.5)</td><td style="text-align:center;">🟡</td><td style="text-align:center;">🟢</td><td style="text-align:center;">🟡</td></tr></tbody></table><p>Legend: 🟢 critical · 🟡 nice-to-have · ⚪ không cần · — không áp dụng</p><hr><h2 id="_6-mapping-persona-→-anchor-decisions-trong-vision" tabindex="-1">6. Mapping persona → Anchor decisions trong Vision <a class="header-anchor" href="#_6-mapping-persona-→-anchor-decisions-trong-vision" aria-label="Permalink to &quot;6. Mapping persona → Anchor decisions trong Vision&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Anchor</th><th>Phục vụ persona</th><th>Cách thể hiện</th></tr></thead><tbody><tr><td><strong>V-01</strong> (MVP tour-only)</td><td>Tất cả 3 personas</td><td>Cả family + young đều book tour, không phải hotel</td></tr><tr><td><strong>V-02</strong> (B2C direct)</td><td>Anh Khoa, Chị Linh</td><td>Trust signal — book trực tiếp với Vivu, không qua trung gian</td></tr><tr><td><strong>V-03</strong> (SEO-first)</td><td>Anh Khoa</td><td>Tìm tour qua Google search là kênh chính của Khoa</td></tr><tr><td><strong>V-04</strong> (Must-login)</td><td>Tất cả</td><td>Trade-off friction để có loyalty + verified review</td></tr><tr><td><strong>V-05</strong> (Hotel content reference)</td><td>Anh Khoa</td><td>Khoa muốn biết hotel cụ thể nào → cần content info, không cần book riêng</td></tr><tr><td><strong>V-06</strong> (Team 2-3 dev)</td><td>Admin Vivu</td><td>Admin Vivu là team nội bộ — UX admin cần ergonomic vì team nhỏ làm nhiều việc</td></tr><tr><td><strong>V-07</strong> (Phase 2 loyalty/affiliate)</td><td>Chị Linh, Anh Khoa</td><td>Loyalty serve repeat customers — cả 2 đều đi nhiều lần/năm</td></tr></tbody></table><hr><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Ngày</th><th>Version</th><th>Thay đổi</th></tr></thead><tbody><tr><td>26/05/2026</td><td>1.0</td><td>Khởi tạo 3 personas (Khoa/Linh/Admin) + journey map B2C + service blueprint + persona-feature matrix</td></tr></tbody></table><hr><p><em>File này thuộc <strong>Tier 1 (Business)</strong>. References:</em></p><ul><li><em>Vision: <a href="./00-tam-nhin"><code>00-tam-nhin.md</code></a></em></li><li><em>BMC: <a href="./00b-mo-hinh-kinh-doanh"><code>00b-mo-hinh-kinh-doanh.md</code></a></em></li><li><em>Strategy: <a href="./01-chien-luoc-tong-the"><code>01-chien-luoc-tong-the.md</code></a></em></li><li><em>Functional design: <a href="./02b-thiet-ke-co-ban"><code>02b-thiet-ke-co-ban.md</code></a> (sitemap + module map)</em></li></ul>`,46)])])}const p=n(a,[["render",i]]);export{u as __pageData,p as default};
